const GlyphPaths: React.FC<{type: AgentType}> = ({type}) => {
  if (type === 'plan') {
    return (
      <>
        <path d="M12 4v4M12 8 6 12v4M12 8l6 4v4M6 16v2M18 16v2" />
        <circle cx="12" cy="4" r="2" />
        <circle cx="6" cy="19" r="2" />
        <circle cx="18" cy="19" r="2" />
      </>
    );
  }

  if (type === 'research') {
    return (
      <>
        <circle cx="10.5" cy="10.5" r="5.5" />
        <path d="m14.6 14.6 4.8 4.8M8 10.5h5M10.5 8v5" />
      </>
    );
  }

  if (type === 'memory') {
    return (
      <>
        <ellipse cx="12" cy="6" rx="7" ry="3" />
        <path d="M5 6v6c0 1.7 3.1 3 7 3s7-1.3 7-3V6M5 12v6c0 1.7 3.1 3 7 3s7-1.3 7-3v-6" />
      </>
    );
  }

  if (type === 'tools') {
    return (
      <>
        <path d="M7.5 5v4M11.5 5v4M6 9h7v1.5a3.5 3.5 0 0 1-3.5 3.5v5" />
        <path d="M16 7h3v3M18.5 7.5l-4 4" />
        <circle cx="9.5" cy="20" r="1.5" />
      </>
    );
  }

  if (type === 'execute') {
    return (
      <>
        <path d="m8 5 10 7-10 7Z" />
        <path d="M4 7v10" />
      </>
    );
  }

  return (
    <>
      <path d="M12 3 19 6v5.4c0 4.5-2.8 7.8-7 9.6-4.2-1.8-7-5.1-7-9.6V6Z" />
      <path d="m8.5 12 2.2 2.2 4.8-5" />
    </>
  );
};

