const MapAgentNode: React.FC<{
  agent: AgentDefinition;
  index: number;
  frame: number;
  fps: number;
}> = ({agent, index, frame, fps}) => {
  const delay = 150 + index * 28;
  const nodeIn = spring({
    frame: frame - delay,
    fps,
    durationInFrames: 48,
    config: {damping: 16, stiffness: 145, mass: 0.75},
  });
  const labelIn = reveal(frame, delay + 20, 34);
  const activity = 0.5 + Math.sin(frame * 0.065 + index * 1.7) * 0.22;
  const ringRotation = frame * (index % 2 === 0 ? 0.12 : -0.1);
  const labelWidth = agent.label === 'RESEARCH' || agent.label === 'TOOL USE' ? 126 : 108;
  const labelX = agent.labelSide === 'left' ? -labelWidth - 42 : agent.labelSide === 'right' ? 42 : -labelWidth / 2;
  const labelY = agent.labelSide === 'top' ? -83 : -23;
  const labelAnchor = agent.labelSide === 'left' ? 'end' : agent.labelSide === 'right' ? 'start' : 'middle';
  const textX = agent.labelSide === 'left' ? -53 : agent.labelSide === 'right' ? 53 : 0;
  const textY = agent.labelSide === 'top' ? -65 : -6;

  return (
    <g transform={`translate(${agent.x} ${agent.y}) scale(${nodeIn})`} opacity={nodeIn}>
      <circle r="31" fill="rgba(3,15,19,.92)" stroke={agent.color} strokeOpacity=".32" strokeWidth="1.2" />
      <circle
        r="25"
        fill={`${agent.color}14`}
        stroke={agent.color}
        strokeOpacity={0.72 + activity * 0.2}
        strokeWidth="1.4"
        strokeDasharray="10 8"
        transform={`rotate(${ringRotation})`}
      />
      <circle r={17 + activity * 2} fill={`${agent.color}10`} />
      <g
        transform="translate(-12 -12)"
        fill="none"
        stroke={agent.color}
        strokeWidth="1.8"
        strokeLinecap="round"
        strokeLinejoin="round"
      >
        <GlyphPaths type={agent.type} />
      </g>

      <g opacity={labelIn} transform={`translate(${(1 - labelIn) * (agent.labelSide === 'left' ? 8 : -8)} 0)`}>
        <rect
          x={labelX}
          y={labelY}
          width={labelWidth}
          height="47"
          rx="11"
          fill="rgba(4,19,24,.91)"
          stroke={agent.color}
          strokeOpacity=".2"
        />
        <text
          x={textX}
          y={textY}
          textAnchor={labelAnchor}
          fill={COLORS.text}
          fontFamily={FONT}
          fontSize="15"
          fontWeight="760"
          letterSpacing="1.2"
        >
          {agent.label}
        </text>
        <text
          x={textX}
          y={textY + 17}
          textAnchor={labelAnchor}
          fill={COLORS.muted}
          fontFamily={FONT}
          fontSize="11.5"
          fontWeight="650"
          letterSpacing="1.1"
        >
          {agent.detail}
        </text>
      </g>
    </g>
  );
};

