export const Motion: React.FC = () => {
  const frame = useCurrentFrame();
  const sceneOut = interpolate(frame, [850, 899], [1, 0], {
    ...clamp,
    easing: Easing.inOut(Easing.cubic),
  });
  const cameraScale = interpolate(frame, [0, 260, 620, 790], [1, 1.018, 1.018, 1], clamp);
  const cameraX = interpolate(frame, [0, 330, 590, 790], [0, -7, -10, 0], clamp);
  const cameraY = interpolate(frame, [0, 330, 590, 790], [0, 4, 3, 0], clamp);

  return (
    <AbsoluteFill style={{fontFamily: FONT, color: COLORS.text, background: COLORS.backgroundDeep}}>
      <Background />
      <AbsoluteFill
        style={{
          opacity: sceneOut,
          transform: `translate(${cameraX}px, ${cameraY}px) scale(${cameraScale})`,
          transformOrigin: '50% 50%',
        }}
      >
        <Header />
        <WorldMap />
        <MapFooter />
        <AgentCorePanel />
      </AbsoluteFill>
      <div
        style={{
          position: 'absolute',
          inset: 0,
          pointerEvents: 'none',
          boxShadow: 'inset 0 0 170px rgba(0,0,0,.45)',
        }}
      />
    </AbsoluteFill>
  );
};
